  violette:  '0aa07f7d88e92682d83f6249a2199b568f39f6101c2ffa4a90df2cd270dd315e@group.calendar.google.com',
};

const now = new Date();
const todayStart = new Date(now); todayStart.setHours(0, 0, 0, 0);
const todayEnd   = new Date(now); todayEnd.setHours(23, 59, 59, 999);
const weekEnd    = new Date(todayStart); weekEnd.setDate(weekEnd.getDate() + 7);

let calendarId = '07281a040c9feb31d96dbaa55c333cebda6a431b5af457c1175ab7645f673f72@group.calendar.google.com';
let timeMin    = todayStart.toISOString();
let timeMax    = todayEnd.toISOString();
let rangeLabel = 'today';

if (calendarArg === 'week') {
  timeMax    = weekEnd.toISOString();
  rangeLabel = 'this week';
} else if (calendarArg && calendarArg !== 'today' && CALENDAR_IDS[calendarArg]) {
  calendarId = CALENDAR_IDS[calendarArg];
  const name = calendarArg.charAt(0).toUpperCase() + calendarArg.slice(1);
  rangeLabel = name + "'s calendar — today";
} else if (calendarArg && calendarArg !== 'today') {
  // Unrecognised arg — still show today, note the confusion
  rangeLabel = 'today (unrecognised filter: ' + calendarArg + ')';
}

return [{ json: { calendarId, timeMin, timeMax, rangeLabel } }];

const items = $input.all();
const rangeLabel = $('Parse Calendar Cmd').first().json.rangeLabel;
const events = items.filter(item => item.json && item.json.id);

if (!events.length) {
  return [{ json: { text: 'Nothing on the calendar for that period.' } }];
}

const TZ = 'America/New_York';

function fmtTime(dateStr) {
  return new Date(dateStr).toLocaleString('en-US', {
    month: 'short', day: 'numeric',
    hour: 'numeric', minute: '2-digit',
    timeZone: TZ,
  });
}

function fmtDate(dateStr) {
  return new Date(dateStr + 'T12:00:00Z').toLocaleString('en-US', {
    month: 'short', day: 'numeric',
    timeZone: TZ,
  });
}

function sameDay(a, b) {
  const da = new Date(a), db = new Date(b);
  return da.toLocaleDateString('en-US', { timeZone: TZ }) ===
         db.toLocaleDateString('en-US', { timeZone: TZ });
}

const lines = events.map(item => {
  const e = item.json;
  const summary = e.summary || '(no title)';
  const start = e.start || {};
  const end   = e.end   || {};
  let dateStr = '';

  if (start.dateTime) {
    const startFmt = fmtTime(start.dateTime);
    if (end.dateTime) {
      if (sameDay(start.dateTime, end.dateTime)) {
        // same day: 'Apr 24, 1:00 PM to 2:00 PM'
        const endTime = new Date(end.dateTime).toLocaleString('en-US', {
          hour: 'numeric', minute: '2-digit', timeZone: TZ,
        });
        dateStr = startFmt + ' to ' + endTime;
      } else {
        dateStr = startFmt + ' to ' + fmtTime(end.dateTime);
      }
    } else {
      dateStr = startFmt;
    }
  } else if (start.date) {
    dateStr = fmtDate(start.date) + ' (all day)';
  }

  let line = '**' + summary + '**';
  if (dateStr) line += ' — ' + dateStr;
  if (e.location) line += '\n📍 ' + e.location;
  if (e.description && e.description.length < 100) line += '\n' + e.description;
  return line;
});

const text = '**Calendar — ' + rangeLabel + '**\n' + lines.join('\n\n');
return [{ json: { text } }];

// Stats come from Query Status (Postgres). Last-error comes from Fetch Last n8n Error (HTTP).
// The HTTP node calls /api/v1/executions?status=error&limit=1&includeData=true
// Response structure: { data: [{ id, startedAt, data: { resultData: { error: {...}, runData: {...} } } }] }
const rows = $('Query Status').all();
const stats = {};
rows.forEach(function(r) { stats[r.json.metric] = r.json.value; });

let lastStr = 'none';
if (stats.last_message && stats.last_message !== 'none') {
  try {
    const d = new Date(stats.last_message);
    lastStr = d.toLocaleString('en-US', {
      timeZone: 'America/New_York',
      month: 'short', day: 'numeric',
      hour: 'numeric', minute: '2-digit',
    }) + ' ET';
  } catch(_) { lastStr = stats.last_message; }
}

let errorBlock = '';
try {
  const errData = $input.first().json;
  const execs = errData && errData.data;
  if (Array.isArray(execs) && execs.length > 0) {
    const ex = execs[0];
    const errTime = new Date(ex.startedAt).toLocaleString('en-US', {
      timeZone: 'America/New_York',
      month: 'short', day: 'numeric',
      hour: 'numeric', minute: '2-digit',
    }) + ' ET';
    // resultData.runData keys = nodes that ran before the error
    const runData = (ex.data && ex.data.resultData && ex.data.resultData.runData) || {};
    const ran = Object.keys(runData);
    const lastNode = ran.length ? ran[ran.length - 1] : 'unknown';
    // resultData.error has the error message
    const errObj = (ex.data && ex.data.resultData && ex.data.resultData.error) || {};
    const errType = errObj.description || errObj.name || '';
    const errMsg = errObj.message ? errObj.message.slice(0, 100) : '';
    const errDetail = errType ? errType + ': ' + errMsg : errMsg;
    errorBlock = '\n\n**Last Error** (' + errTime + ')' +
      '\n  Last OK node: ' + lastNode +
      (errDetail ? ('\n  Error: ' + errDetail) : '');
  }
} catch(_) {}

const lines = [
  '**Bruce Status**',
  '',
  '**Messages**',
  '  Last activity: ' + lastStr,
  '  Past 24h: ' + (stats.messages_24h || '0'),
  '  Past 7d:  ' + (stats.messages_7d  || '0'),
  '',
  '**Memories**',
  '  Total: ' + (stats.memories_total  || '0'),
  '  Auto-extracted: ' + (stats.memories_auto   || '0'),
  '  Manual: ' + (stats.memories_manual || '0'),
  '',
  '**Recipes**',
  '  Total: ' + (stats.recipes_total || '0'),
];

return [{ json: { commandReply: lines.join('\n') + errorBlock } }];

// Format the recipes list for Discord. Split into ≤1900-char chunks.
const rows = $input.all();
const router = $('Channel Router').first().json;

if (!rows.length || (rows.length === 1 && !rows[0].json.id)) {
  const msg = router.recipesQuery
    ? 'No recipes match that search.'
    : 'No recipes saved yet. Use `/save-recipe Title` then Shift+Enter and type the body.';
  return [{ json: { ...router, commandReply: msg } }];
}

const lines = rows.map(function(r) {
  const title   = r.json.title   || '(untitled)';
  const preview = r.json.preview || '';
  const id      = r.json.id;
  return '**' + id + '. ' + title + '**' + (preview ? ('\n' + preview) : '');
});

const MAX = 1900;
const chunks = [];
let cur = '';
lines.forEach(function(line) {
  const sep = cur ? '\n\n' : '';
  if ((cur + sep + line).length > MAX) {
    if (cur) chunks.push(cur);
    cur = line;
  } else {
    cur += sep + line;
  }
});
if (cur) chunks.push(cur);

return chunks.map(function(chunk) {
  return { json: { ...router, commandReply: chunk } };
});

// Parse /private — decide desired new mode (on/off), build commandReply.
// Upstream Channel Router has already read current flag state via Query
// Session Flags and surfaced it as router.skipPersist (true if currently
// private). privateArg is 'on' | 'off' | null (toggle).
const router = $('Channel Router').first().json;
const wasPrivate = router.skipPersist === true;
const arg = router.privateArg;  // null means toggle

let newValue;
if (arg === 'on') newValue = true;
else if (arg === 'off') newValue = false;
else newValue = !wasPrivate;

const turnedOff = wasPrivate && !newValue;
const nowIso = new Date().toISOString();

let commandReply;
if (newValue) {
  commandReply = '\uD83D\uDD12 Private mode on — this conversation won\'t be saved or remembered.';
} else if (turnedOff) {
  commandReply = '\uD83D\uDD13 Private mode off — my messages from this session have been deleted. Back to normal.';
} else {
  commandReply = '\uD83D\uDD13 Private mode off — back to normal.';
}

return [{ json: {
  ...router,
  privateNewValue: newValue ? 'true' : 'false',
  privateNewValueBool: newValue,
  privateTurnedOff: turnedOff,
  privateStartedAtNew: newValue ? (router.privateStartedAt || nowIso) : nowIso,
  commandReply,
} }];

// Cleanup Bot Messages — delete the bot's messages sent during a /private
// session, triggered on /private off. Pass-through when privateTurnedOff
// is false so the reply still goes out.
const router = $('Parse Private Cmd').first().json;
const passthrough = [{ json: router }];

if (!router.privateTurnedOff) return passthrough;

const BOT_TOKEN   = $env.DISCORD_BOT_TOKEN;
const BOT_USER_ID = '1495252972026859520';
const channelId   = router.channelId;
const sinceIso    = router.privateStartedAt;  // original session start
if (!BOT_TOKEN || !channelId || !sinceIso) return passthrough;

const headers = {
  Authorization: 'Bot ' + BOT_TOKEN,
  'User-Agent': 'household-ai (bruce, 1.0)',
};

try {
  const listRes = await fetch('https://discord.com/api/v10/channels/' + channelId + '/messages?limit=100', { headers });
  if (!listRes.ok) return passthrough;
  const messages = await listRes.json();
  const sinceMs = Date.parse(sinceIso);
  const targets = (messages || []).filter(m =>
    m && m.author && m.author.id === BOT_USER_ID &&
    Date.parse(m.timestamp) >= sinceMs
  );
  for (const m of targets) {
    try {
      await fetch('https://discord.com/api/v10/channels/' + channelId + '/messages/' + m.id, { method: 'DELETE', headers });
    } catch (_) { /* swallow per-message failures */ }
  }
} catch (_) { /* swallow list failures */ }

return passthrough;

// Purge Messages — delete recent messages in the current channel via
// Discord REST API. Server channels use bulk-delete (messages <14d old);
// DMs fall back to deleting only the bot's own messages (Discord does
// not allow bots to delete other users' DM messages).
const router  = $('Channel Router').first().json;
const arg     = router.purgeArg;            // number | 'all'
const isDm    = router.isDm === true;
const BOT_TOKEN   = $env.DISCORD_BOT_TOKEN;
const BOT_USER_ID = '1495252972026859520';
const channelId   = router.channelId;

if (!BOT_TOKEN || !channelId) {
  return [{ json: { ...router, commandReply: '\u274C Could not reach Discord — missing bot token or channel.' } }];
}

const headers = {
  Authorization: 'Bot ' + BOT_TOKEN,
  'Content-Type': 'application/json',
  'User-Agent': 'household-ai (bruce, 1.0)',
};

const limitToFetch = arg === 'all' ? 100 : Math.min(arg, 100);
const cutoffMs     = Date.now() - 14 * 24 * 3600 * 1000;

async function listMessages() {
  const r = await fetch('https://discord.com/api/v10/channels/' + channelId + '/messages?limit=' + limitToFetch, { headers });
  if (!r.ok) return [];
  return await r.json();
}

async function deleteOne(id) {
  try {
    await fetch('https://discord.com/api/v10/channels/' + channelId + '/messages/' + id, { method: 'DELETE', headers });
    return true;
  } catch (_) { return false; }
}

async function bulkDelete(ids) {
  if (ids.length === 0) return 0;
  if (ids.length === 1) return (await deleteOne(ids[0])) ? 1 : 0;
  try {
    const r = await fetch('https://discord.com/api/v10/channels/' + channelId + '/messages/bulk-delete', {
      method: 'POST', headers, body: JSON.stringify({ messages: ids }),
    });
    return r.ok ? ids.length : 0;
  } catch (_) { return 0; }
}

let deleted = 0;
let dmNote  = '';

try {
  const messages = await listMessages();
  if (isDm) {
    const mine = messages.filter(m => m.author && m.author.id === BOT_USER_ID);
    for (const m of mine) { if (await deleteOne(m.id)) deleted++; }
    dmNote = '\nDiscord doesn\'t allow bots to delete your messages in DMs — you can delete yours by right-clicking them (they disappear from both sides).';
  } else {
    const recent = messages.filter(m => Date.parse(m.timestamp) >= cutoffMs);
    const bulkable = recent.filter(m => Date.parse(m.timestamp) >= cutoffMs).map(m => m.id);
    // bulk-delete only supports 2..100 messages <14d old
    const chunks = [];
    for (let i = 0; i < bulkable.length; i += 100) chunks.push(bulkable.slice(i, i + 100));
    for (const chunk of chunks) deleted += await bulkDelete(chunk);
  }
} catch (_) { /* swallow */ }

const body = '\uD83D\uDDD1\uFE0F Deleted ' + deleted + ' message' + (deleted === 1 ? '' : 's') + '.' + dmNote +
  '\n\n_History in Postgres is untouched — run \\`/clear\\` to also wipe conversation history._';

return [{ json: { ...router, commandReply: body } }];
